query:
_view=sumologic_search_usage_per_query query_type="Interactive Dashboard"
//| where data_scanned_bytes > (1 * 1G)
//| (query_end_time - query_start_time)/1000 as range_s
//| execution_duration_ms /1000 as duration_s
| if(isempty(content_name),substring(query,0,200),content_name) as item
| if(status_message = "Finished successfully",0,1) as fail

| count_distinct(query) as unique_queries,max(scanned_partition_count) as max_partitions,count_distinct(user_name) as users,count as searches, sum(data_scanned_bytes) as bytes_scanned,   sum(fail) as %"fail/cancelled" by user_name,query_type,item
//| replace (partitions,"\n",", ") as partitions
| sort bytes_scanned
| bytes_scanned / 1024/1024/1024/1024 as scan_tb
| fields -bytes_scanned,unique_queries,users,query_type
